```class Solution {
    public String maximumBinaryString(String binary) {
        int ones = 0, zeros = 0;
        for (char c : binary.toCharArray()) {
            if (c == '0') zeros++;
            else ones++;
        }
        StringBuilder res = new StringBuilder();
        while (zeros > 0) {
            res.append('1');
            zeros--;
        }
        res.append(ones, 0, ones);
        while (zeros > 0) {
            res.insert(0, '0');
            zeros--;
        }
        return res.toString();
    }
}```
